example_bad:
enum List {
    Cons(i32, List), // Error: recursive without indirection
    Nil,
}

struct Tree {
    value: i32,
    left: Tree, // Error: infinite size
    right: Tree,
}

fixes.code:
enum List {
    Cons(i32, Box<List>), // Box has a known size (pointer)
    Nil,
}

struct Tree {
    value: i32,
    left: Option<Box<Tree>>,
    right: Option<Box<Tree>>,
}

use std::rc::Rc;

enum List {
    Cons(i32, Rc<List>),
    Nil,
}
